package com.example.health_app.ml

import com.example.health_app.BuildConfig
import com.example.health_app.data.Meritev
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.BufferedReader
import java.io.InputStreamReader
import java.net.HttpURLConnection
import java.net.URL
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class GeminiHelper {

    private val apiKey: String = BuildConfig.GEMINI_API_KEY
    private val endpoint = "https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent"

    suspend fun generateSummary(meritve: List<Meritev>): String {
        if (apiKey.isBlank()) {
            return generateLocalSummary(meritve, includeFallbackNote = true)
        }
        if (meritve.isEmpty()) {
            return "Ni meritev za povzetek."
        }

        return runCatching {
            val input = meritve
                .sortedByDescending { it.datum }
                .take(10)
                .joinToString("\n") { m ->
                    "- datum=${formatDate(m.datum)}, srcniUtrip=${m.srcniUtrip}, spo2=${m.spO2}, temperatura=${"%.1f".format(m.temperatura)}"
                }

            val prompt = """
                Si zdravstveni asistent. Na podlagi spodnjih meritev napiši kratek povzetek v slovenščini (2-4 stavke).
                Ne postavljaj diagnoze. Opiši trend in opozori na možna odstopanja.

                Meritve:
                $input
            """.trimIndent()

            val response = callGeminiRest(prompt)
            extractGeminiText(response)?.trim().orEmpty().ifBlank {
                generateLocalSummary(meritve, includeFallbackNote = true)
            }
        }.getOrElse {
            generateLocalSummary(meritve, includeFallbackNote = true)
        }
    }

    private suspend fun callGeminiRest(prompt: String): String = withContext(Dispatchers.IO) {
        val url = URL(endpoint)
        val body = JSONObject()
            .put(
                "contents",
                org.json.JSONArray().put(
                    JSONObject().put(
                        "parts",
                        org.json.JSONArray().put(JSONObject().put("text", prompt))
                    )
                )
            )
            .toString()

        val connection = (url.openConnection() as HttpURLConnection).apply {
            requestMethod = "POST"
            connectTimeout = 15_000
            readTimeout = 30_000
            doInput = true
            doOutput = true
            setRequestProperty("Content-Type", "application/json; charset=utf-8")
            setRequestProperty("x-goog-api-key", apiKey)
        }

        try {
            connection.outputStream.use { os ->
                os.write(body.toByteArray(Charsets.UTF_8))
            }

            val stream = if (connection.responseCode in 200..299) {
                connection.inputStream
            } else {
                connection.errorStream ?: connection.inputStream
            }

            BufferedReader(InputStreamReader(stream)).use { reader ->
                reader.readText()
            }
        } finally {
            connection.disconnect()
        }
    }

    private fun extractGeminiText(rawResponse: String): String? {
        if (rawResponse.isBlank()) return null
        return runCatching {
            val root = JSONObject(rawResponse)
            val candidates = root.optJSONArray("candidates") ?: return null
            val firstCandidate = candidates.optJSONObject(0) ?: return null
            val content = firstCandidate.optJSONObject("content") ?: return null
            val parts = content.optJSONArray("parts") ?: return null
            val firstPart = parts.optJSONObject(0) ?: return null
            firstPart.optString("text").takeIf { it.isNotBlank() }
        }.getOrNull()
    }

    private fun generateLocalSummary(
        meritve: List<Meritev>,
        includeFallbackNote: Boolean
    ): String {
        if (meritve.isEmpty()) return "Ni meritev za povzetek."

        val sorted = meritve.sortedByDescending { it.datum }.take(10)
        val avgHr = sorted.map { it.srcniUtrip }.average()
        val avgSpo2 = sorted.map { it.spO2 }.average()
        val avgTemp = sorted.map { it.temperatura }.average()
        val latest = sorted.first()

        val healthNote = when {
            avgHr >= 100 || avgSpo2 < 95 || avgTemp >= 37.5 ->
                "Nekatere meritve odstopajo od običajnega razpona in jih je smiselno spremljati."
            else ->
                "Meritve so večinoma v normalnem razponu."
        }

        val fallbackNote = if (includeFallbackNote) {
            " Gemini ni bil na voljo, zato je prikazan lokalni povzetek."
        } else {
            ""
        }

        return buildString {
            append("Na podlagi zadnjih ")
            append(sorted.size)
            append(" meritev je povprečni srčni utrip ")
            append("%.0f".format(avgHr))
            append(" bpm, povprečni SpO₂ ")
            append("%.0f".format(avgSpo2))
            append(" %, temperatura pa ")
            append("%.1f".format(avgTemp))
            append(" °C. ")
            append(healthNote)
            append(" Zadnja meritev je bila zabeležena ")
            append(formatDate(latest.datum))
            append(".")
            append(fallbackNote)
        }
    }

    private fun formatDate(timestamp: Long): String {
        return SimpleDateFormat("dd.MM.yyyy", Locale.getDefault()).format(Date(timestamp))
    }
}

package com.example.health_app.ml

import android.content.Context
import android.util.Log
import org.tensorflow.lite.Interpreter
import java.io.FileInputStream
import java.nio.MappedByteBuffer
import java.nio.channels.FileChannel
import kotlin.math.exp

enum class HealthStatus {
    NORMAL,
    ELEVATED,
    CRITICAL
}

data class HealthPrediction(
    val status: HealthStatus,
    val confidence: Map<HealthStatus, Float>,
    val fromTflite: Boolean
)

class HealthClassifier(private val context: Context) {

    private val interpreter: Interpreter? by lazy {
        runCatching {
            Interpreter(loadModelFile("health_classifier.tflite"))
        }.onFailure {
            Log.w("HealthClassifier", "TFLite model not available, using rule-based fallback", it)
        }.getOrNull()
    }

    fun classify(hr: Int, spo2: Int, temp: Double): HealthPrediction {
        val tflitePrediction = runTflite(hr, spo2, temp)
        return tflitePrediction ?: classifyRuleBased(hr, spo2, temp)
    }

    private fun runTflite(hr: Int, spo2: Int, temp: Double): HealthPrediction? {
        val model = interpreter ?: return null
        return runCatching {
            val input = arrayOf(floatArrayOf(hr.toFloat(), spo2.toFloat(), temp.toFloat()))
            val output = Array(1) { FloatArray(3) }
            model.run(input, output)

            val probs = softmax(output[0])
            val confidenceMap = mapOf(
                HealthStatus.NORMAL to probs[0],
                HealthStatus.ELEVATED to probs[1],
                HealthStatus.CRITICAL to probs[2]
            )

            val status = confidenceMap.maxByOrNull { it.value }?.key ?: HealthStatus.ELEVATED
            HealthPrediction(status = status, confidence = confidenceMap, fromTflite = true)
        }.onFailure {
            Log.e("HealthClassifier", "TFLite inference failed, using rule fallback", it)
        }.getOrNull()
    }

    private fun classifyRuleBased(hr: Int, spo2: Int, temp: Double): HealthPrediction {
        val status = when {
            hr > 120 || spo2 < 90 || temp > 39.0 -> HealthStatus.CRITICAL
            hr > 100 || spo2 < 95 || temp > 37.5 -> HealthStatus.ELEVATED
            else -> HealthStatus.NORMAL
        }

        val confidenceMap = when (status) {
            HealthStatus.NORMAL -> mapOf(
                HealthStatus.NORMAL to 0.90f,
                HealthStatus.ELEVATED to 0.08f,
                HealthStatus.CRITICAL to 0.02f
            )

            HealthStatus.ELEVATED -> mapOf(
                HealthStatus.NORMAL to 0.15f,
                HealthStatus.ELEVATED to 0.75f,
                HealthStatus.CRITICAL to 0.10f
            )

            HealthStatus.CRITICAL -> mapOf(
                HealthStatus.NORMAL to 0.05f,
                HealthStatus.ELEVATED to 0.15f,
                HealthStatus.CRITICAL to 0.80f
            )
        }

        return HealthPrediction(status = status, confidence = confidenceMap, fromTflite = false)
    }

    private fun loadModelFile(fileName: String): MappedByteBuffer {
        context.assets.openFd(fileName).use { fileDescriptor ->
            FileInputStream(fileDescriptor.fileDescriptor).use { inputStream ->
                val fileChannel = inputStream.channel
                return fileChannel.map(
                    FileChannel.MapMode.READ_ONLY,
                    fileDescriptor.startOffset,
                    fileDescriptor.declaredLength
                )
            }
        }
    }

    private fun softmax(values: FloatArray): FloatArray {
        val max = values.maxOrNull() ?: 0f
        val exps = values.map { exp((it - max).toDouble()).toFloat() }
        val sum = exps.sum().takeIf { it > 0f } ?: 1f
        return exps.map { it / sum }.toFloatArray()
    }
}

package com.example.health_app.network

import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

private const val BASE_URL = "https://mocki.io/v1/"

data class HeartRateResponse(val value: Int)
data class SpO2Response(val value: Int)
data class TemperatureResponse(val value: Double)

interface MockHealthApi {
    @GET("heartrate")
    suspend fun getHeartRate(): HeartRateResponse

    @GET("spo2")
    suspend fun getSpO2(): SpO2Response

    @GET("temperature")
    suspend fun getTemperature(): TemperatureResponse
}

object MockHealthApiProvider {
    val api: MockHealthApi by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(MockHealthApi::class.java)
    }
}

package com.example.health_app.network

import android.content.Context
import android.hardware.Sensor
import android.hardware.SensorEvent
import android.hardware.SensorEventListener
import android.hardware.SensorManager
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import kotlinx.coroutines.withTimeoutOrNull
import kotlin.coroutines.resume
import kotlin.random.Random

class SensorRepository(
	context: Context,
	private val api: MockHealthApi = MockHealthApiProvider.api
) {
	private val sensorManager = context.getSystemService(Context.SENSOR_SERVICE) as SensorManager

	fun hasHeartRateSensor(): Boolean {
		return sensorManager.getDefaultSensor(Sensor.TYPE_HEART_RATE) != null
	}

	suspend fun readHeartRateFromSensor(): Int? {
		val sensor = sensorManager.getDefaultSensor(Sensor.TYPE_HEART_RATE) ?: return null

		return withTimeoutOrNull(4000L) {
			suspendCancellableCoroutine { continuation ->
				val listener = object : SensorEventListener {
					override fun onSensorChanged(event: SensorEvent?) {
						val value = event?.values?.firstOrNull()?.toInt()
						if (value != null && value > 0 && continuation.isActive) {
							sensorManager.unregisterListener(this)
							continuation.resume(value)
						}
					}

					override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) = Unit
				}

				sensorManager.registerListener(listener, sensor, SensorManager.SENSOR_DELAY_NORMAL)
				continuation.invokeOnCancellation {
					sensorManager.unregisterListener(listener)
				}
			}
		}
	}

	suspend fun readHeartRateFromApi(): Int = withContext(Dispatchers.IO) {
		runCatching { api.getHeartRate().value }.getOrElse { Random.nextInt(60, 101) }
	}

	suspend fun readSpO2FromApi(): Int = withContext(Dispatchers.IO) {
		runCatching { api.getSpO2().value }.getOrElse { Random.nextInt(94, 100) }
	}

	suspend fun readTemperatureFromApi(): Double = withContext(Dispatchers.IO) {
		runCatching { api.getTemperature().value }.getOrElse { Random.nextDouble(36.0, 37.8) }
	}
}

