@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun StatisticsScreen(
    viewModel: MeritevViewModel,
    onNavigateBack: () -> Unit
) {
    val statistics by viewModel.statistics.collectAsStateWithLifecycle()
    val cloudMeritve by viewModel.cloudMeritve.collectAsStateWithLifecycle()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(stringResource(R.string.statistika)) },
                navigationIcon = {
                    IconButton(onClick = onNavigateBack) {
                        Icon(
                            imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                            contentDescription = stringResource(R.string.preklici)
                        )
                    }
                }
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(horizontal = 16.dp, vertical = 12.dp)
                .verticalScroll(rememberScrollState())
        ) {
            // Srčni utrip stats
            StatisticsCard(
                title = stringResource(R.string.srcni_utrip),
                avgValue = statistics.avgSrcniUtrip,
                minValue = statistics.minSrcniUtrip.toString(),
                maxValue = statistics.maxSrcniUtrip.toString(),
                unit = "bpm"
            )

            Spacer(modifier = Modifier.height(16.dp))

            // SpO2 stats
            StatisticsCard(
                title = stringResource(R.string.spo2),
                avgValue = statistics.avgSpO2,
                minValue = statistics.minSpO2.toString(),
                maxValue = statistics.maxSpO2.toString(),
                unit = "%"
            )

            Spacer(modifier = Modifier.height(16.dp))

            // Temperatura stats
            StatisticsCard(
                title = stringResource(R.string.temperatura),
                avgValue = statistics.avgTemperatura,
                minValue = String.format("%.1f", statistics.minTemperatura),
                maxValue = String.format("%.1f", statistics.maxTemperatura),
                unit = "°C"
            )

            Spacer(modifier = Modifier.height(16.dp))

            // Total measurements
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(vertical = 8.dp),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.surfaceVariant
                )
            ) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        text = stringResource(R.string.skupno_meritev),
                        style = MaterialTheme.typography.bodyMedium,
                        fontWeight = FontWeight.Medium
                    )
                    Text(
                        text = statistics.totalMeritve.toString(),
                        style = MaterialTheme.typography.bodyMedium,
                        fontWeight = FontWeight.Bold,
                        color = MaterialTheme.colorScheme.primary
                    )
                }
            }

            Spacer(modifier = Modifier.height(24.dp))

            // Chart section (if there's data)
            if (cloudMeritve.isNotEmpty()) {
                Text(
                    text = stringResource(R.string.trend_meritev),
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(vertical = 12.dp)
                )

                // Simple line chart data - Srčni utrip over time
                val chartData = cloudMeritve
                    .mapIndexed { index, meritev ->
                        index.toFloat() to meritev.srcniUtrip.toFloat()
                    }

                if (chartData.isNotEmpty()) {
                    val modelProducer = CartesianChartModelProducer.build {
                        lineSeries {
                            series(chartData.map { it.second })
                        }
                    }

                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(300.dp),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.surface
                        )
                    ) {
                        Box(modifier = Modifier.fillMaxSize()) {
                            CartesianChartHost(
                                modelProducer = modelProducer,
                                chart = rememberCartesianChart(
                                    rememberLineCartesianLayerComponent()
                                ),
                                modifier = Modifier
                                    .fillMaxSize()
                                    .padding(16.dp),
                                zoom = Zoom.Content
                            )
                        }
                    }
                }
            }
        }
    }
}

