@Composable
private fun SimpleLineChart(
    values: List<Float>,
    modifier: Modifier = Modifier
) {
    Canvas(modifier = modifier) {
        if (values.isEmpty()) return@Canvas

        val minValue = values.minOrNull() ?: 0f
        val maxValue = values.maxOrNull() ?: 0f
        val range = if (maxValue - minValue == 0f) 1f else maxValue - minValue
        val stepX = if (values.size == 1) 0f else size.width / (values.size - 1)

        val points = values.mapIndexed { index, value ->
            val x = if (values.size == 1) size.width / 2f else index * stepX
            val normalized = (value - minValue) / range
            val y = size.height - (normalized * size.height)
            Offset(x, y)
        }

        // background grid
        val gridColor = Color.Gray.copy(alpha = 0.18f)
        repeat(3) { index ->
            val y = size.height * (index + 1) / 4f
            drawLine(
                color = gridColor,
                start = Offset(0f, y),
                end = Offset(size.width, y),
                strokeWidth = 1f
            )
        }

        for (i in 0 until points.lastIndex) {
            drawLine(
                color = Color(0xFF1976D2),
                start = points[i],
                end = points[i + 1],
                strokeWidth = 6f
            )
        }

        points.forEach { point ->
            drawCircle(
                color = Color(0xFF1565C0),
                radius = 7f,
                center = point
            )
            drawCircle(
                color = Color.White,
                radius = 2.5f,
                center = point
            )
        }

        // frame
        drawRect(
            color = Color.Gray.copy(alpha = 0.25f),
            style = Stroke(width = 2f)
        )
    }
}

