import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun VnosMeritveScreen(
    viewModel: MeritevViewModel,
    meritevId: Int? = null,
    onNavigateToDetail: (Int) -> Unit,
    onNavigateToList: () -> Unit
) {
    val snackbarHostState = remember { SnackbarHostState() }

    // Form state
    var ime by rememberSaveable { mutableStateOf("") }
    var priimek by rememberSaveable { mutableStateOf("") }
    var datum by rememberSaveable { mutableStateOf(System.currentTimeMillis()) }
    var srcniUtripText by rememberSaveable { mutableStateOf("") }
    var spO2Text by rememberSaveable { mutableStateOf("") }
    var temperaturaText by rememberSaveable { mutableStateOf("") }

    // Error state
    var imeError by rememberSaveable { mutableStateOf(false) }
    var priimekError by rememberSaveable { mutableStateOf(false) }
    var srcniUtripError by rememberSaveable { mutableStateOf<String?>(null) }
    var spO2Error by rememberSaveable { mutableStateOf<String?>(null) }
    var temperaturaError by rememberSaveable { mutableStateOf<String?>(null) }

    var showDatePicker by rememberSaveable { mutableStateOf(false) }
    var isLoaded by rememberSaveable { mutableStateOf(false) }
    var newlyInsertedId by rememberSaveable { mutableStateOf<Int?>(null) }
    var existingUserId by rememberSaveable { mutableStateOf("") }
    var existingFirestoreId by rememberSaveable { mutableStateOf("") }

    fun resetForm() {
        ime = ""
        priimek = ""
        datum = System.currentTimeMillis()
        srcniUtripText = ""
        spO2Text = ""
        temperaturaText = ""

        imeError = false
        priimekError = false
        srcniUtripError = null
        spO2Error = null
        temperaturaError = null
    }

    // Load existing measurement for editing
    if (meritevId != null && !isLoaded) {
        val meritev by viewModel.getMeritevById(meritevId)
            .collectAsStateWithLifecycle(initialValue = null)
        meritev?.let {
            ime = it.ime
            priimek = it.priimek
            datum = it.datum
            srcniUtripText = it.srcniUtrip.toString()
            spO2Text = it.spO2.toString()
            temperaturaText = it.temperatura.toString()
            existingUserId = it.userId
            existingFirestoreId = it.firestoreId
            isLoaded = true
        }
    }

    // Observe operation result for snackbar
    val operationResult by viewModel.operationResult.collectAsStateWithLifecycle()
    val msgShranjena = stringResource(R.string.meritev_shranjena)
    val msgPosodobljena = stringResource(R.string.meritev_posodobljena)
    val msgNapaka = stringResource(R.string.napaka_shranjevanja)
    val statusMessage by viewModel.statusMessage.collectAsStateWithLifecycle(initialValue = null)

    LaunchedEffect(statusMessage) {
        statusMessage?.let { snackbarHostState.showSnackbar(it) }
    }

    LaunchedEffect(operationResult) {
        when (operationResult) {
            MeritevViewModel.OperationResult.INSERTED -> {
                snackbarHostState.showSnackbar(msgShranjena)
                viewModel.clearOperationResult()
                resetForm()
                newlyInsertedId?.let(onNavigateToDetail) ?: onNavigateToList()
                newlyInsertedId = null
            }
            MeritevViewModel.OperationResult.UPDATED -> {
                snackbarHostState.showSnackbar(msgPosodobljena)
                viewModel.clearOperationResult()
                if (meritevId != null) {
                    onNavigateToDetail(meritevId)
                } else {
                    onNavigateToList()
                }
            }
            MeritevViewModel.OperationResult.ERROR -> {
                snackbarHostState.showSnackbar(msgNapaka)
                viewModel.clearOperationResult()
            }
            else -> {}
        }
    }

    val dateFormat = SimpleDateFormat("dd.MM.yyyy", Locale.getDefault())

    // Validation strings
    val poljeObvezno = stringResource(R.string.polje_obvezno)
    val srcniUtripNapaka = stringResource(R.string.srcni_utrip_napaka)
    val spO2Napaka = stringResource(R.string.spo2_napaka)
    val temperaturaNapaka = stringResource(R.string.temperatura_napaka)
    val neveljavenVnos = stringResource(R.string.neveljaven_vnos)

    val title = if (meritevId != null) stringResource(R.string.uredi_meritev)
                else stringResource(R.string.nova_meritev)

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(horizontal = 24.dp, vertical = 16.dp)
                .verticalScroll(rememberScrollState())
        ) {
            Text(
                text = title,
                style = MaterialTheme.typography.headlineMedium
            )

            Spacer(modifier = Modifier.height(24.dp))

            // Ime
            OutlinedTextField(
                value = ime,
                onValueChange = {
                    ime = it
                    imeError = false
                },
                label = { Text(stringResource(R.string.ime)) },
                isError = imeError,
                supportingText = if (imeError) ({ Text(poljeObvezno) }) else null,
                modifier = Modifier.fillMaxWidth(),
                singleLine = true
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Priimek
            OutlinedTextField(
                value = priimek,
                onValueChange = {
                    priimek = it
                    priimekError = false
                },
                label = { Text(stringResource(R.string.priimek)) },
                isError = priimekError,
                supportingText = if (priimekError) ({ Text(poljeObvezno) }) else null,
                modifier = Modifier.fillMaxWidth(),
                singleLine = true
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Datum
            OutlinedTextField(
                value = dateFormat.format(Date(datum)),
                onValueChange = {},
                label = { Text(stringResource(R.string.datum_meritve)) },
                readOnly = true,
                trailingIcon = {
                    IconButton(onClick = { showDatePicker = true }) {
                        Icon(
                            imageVector = Icons.Default.DateRange,
                            contentDescription = stringResource(R.string.datum_meritve)
                        )
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Srčni utrip
            SensorInputRow(
                value = srcniUtripText,
                onValueChange = {
                    srcniUtripText = it
                    srcniUtripError = null
                },
                label = stringResource(R.string.srcni_utrip),
                keyboardType = KeyboardType.Number,
                isError = srcniUtripError != null,
                supportingText = srcniUtripError,
                sensorButtonDescription = stringResource(R.string.preberi_srcni_utrip),
                onSensorRead = {
                    viewModel.preberiSrcniUtrip { value -> srcniUtripText = value.toString() }
                }
            )

            Spacer(modifier = Modifier.height(12.dp))

            // SpO2
            SensorInputRow(
                value = spO2Text,
                onValueChange = {
                    spO2Text = it
                    spO2Error = null
                },
                label = stringResource(R.string.spo2),
                keyboardType = KeyboardType.Number,
                isError = spO2Error != null,
                supportingText = spO2Error,
                sensorButtonDescription = stringResource(R.string.preberi_spo2),
                onSensorRead = {
                    viewModel.preberiSpO2 { value -> spO2Text = value.toString() }
                }
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Temperatura
            SensorInputRow(
                value = temperaturaText,
                onValueChange = {
                    temperaturaText = it
                    temperaturaError = null
                },
                label = stringResource(R.string.temperatura),
                keyboardType = KeyboardType.Decimal,
                isError = temperaturaError != null,
                supportingText = temperaturaError,
                sensorButtonDescription = stringResource(R.string.preberi_temperaturo),
                onSensorRead = {
                    viewModel.preberiTemperaturo { value ->
                        temperaturaText = String.format(Locale.US, "%.1f", value)
                    }
                }
            )

            Spacer(modifier = Modifier.height(24.dp))

            // Save button
            Button(
                onClick = {
                    // Validate
                    var isValid = true

                    if (ime.isBlank()) {
                        imeError = true
                        isValid = false
                    }
                    if (priimek.isBlank()) {
                        priimekError = true
                        isValid = false
                    }

                    val srcniUtrip = srcniUtripText.toIntOrNull()
                    if (srcniUtrip == null) {
                        srcniUtripError = neveljavenVnos
                        isValid = false
                    } else if (srcniUtrip < 30 || srcniUtrip > 250) {
                        srcniUtripError = srcniUtripNapaka
                        isValid = false
                    }

                    val spO2 = spO2Text.toIntOrNull()
                    if (spO2 == null) {
                        spO2Error = neveljavenVnos
                        isValid = false
                    } else if (spO2 < 0 || spO2 > 100) {
                        spO2Error = spO2Napaka
                        isValid = false
                    }

                    val temperatura = temperaturaText.replace(",", ".").toDoubleOrNull()
                    if (temperatura == null) {
                        temperaturaError = neveljavenVnos
                        isValid = false
                    } else if (temperatura < 34.0 || temperatura > 42.0) {
                        temperaturaError = temperaturaNapaka
                        isValid = false
                    }

                    if (isValid) {
                        val meritev = Meritev(
                            id = meritevId ?: 0,
                            ime = ime.trim(),
                            priimek = priimek.trim(),
                            datum = datum,
                            srcniUtrip = srcniUtrip!!,
                            spO2 = spO2!!,
                            temperatura = temperatura!!,
                            userId = existingUserId,
                            firestoreId = existingFirestoreId
                        )
                        if (meritevId != null) {
                            viewModel.posodobi(meritev)
                        } else {
                            viewModel.vstavi(meritev) { id ->
                                newlyInsertedId = id
                                resetForm()
                            }
                        }
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.primary
                )
            ) {
                Text(stringResource(R.string.shrani_meritev))
            }

            Spacer(modifier = Modifier.height(12.dp))

            // List button
            OutlinedButton(
                onClick = onNavigateToList,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text(stringResource(R.string.btn_seznam_meritev))
            }
        }
    }

    // Date Picker Dialog
    if (showDatePicker) {
        val datePickerState = rememberDatePickerState(initialSelectedDateMillis = datum)
        DatePickerDialog(
            onDismissRequest = { showDatePicker = false },
            confirmButton = {
                TextButton(onClick = {
                    datePickerState.selectedDateMillis?.let {
                        datum = it
                    }
                    showDatePicker = false
                }) {
                    Text(stringResource(R.string.potrdi))
                }
            },
            dismissButton = {
                TextButton(onClick = { showDatePicker = false }) {
                    Text(stringResource(R.string.preklici))
                }
            }
        ) {
            DatePicker(state = datePickerState)
        }
    }
}

@Composable
private fun SensorInputRow(
    value: String,
    onValueChange: (String) -> Unit,
    label: String,
    keyboardType: KeyboardType,
    isError: Boolean,
    supportingText: String?,
    sensorButtonDescription: String,
    onSensorRead: () -> Unit
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        verticalAlignment = Alignment.CenterVertically
    ) {
        OutlinedTextField(
            value = value,
            onValueChange = onValueChange,
            label = { Text(label) },
            keyboardOptions = KeyboardOptions(keyboardType = keyboardType),
            isError = isError,
            supportingText = supportingText?.let { error -> { Text(error) } },
            modifier = Modifier.weight(1f),
            singleLine = true
        )

        Spacer(modifier = Modifier.width(8.dp))

        FilledTonalButton(
            onClick = onSensorRead,
            shape = RoundedCornerShape(20.dp),
            modifier = Modifier.size(width = 64.dp, height = 56.dp),
            contentPadding = ButtonDefaults.ContentPadding
        ) {
            Icon(
                imageVector = Icons.Default.Refresh,
                contentDescription = sensorButtonDescription,
                modifier = Modifier.size(20.dp)
            )
        }
    }

    if (supportingText != null) {
        Text(
            text = supportingText,
            color = MaterialTheme.colorScheme.error,
            style = MaterialTheme.typography.bodySmall,
            textAlign = TextAlign.Start,
            modifier = Modifier
                .fillMaxWidth()
                .padding(start = 16.dp, top = 2.dp)
        )
    }
}

package com.example.health_app.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.health_app.R
import com.example.health_app.data.FirestoreRepository
import com.example.health_app.data.Meritev
import com.example.health_app.data.MeritevRepository
import com.example.health_app.data.Statistics
import com.example.health_app.network.SensorRepository
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.emptyFlow
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

@OptIn(kotlinx.coroutines.ExperimentalCoroutinesApi::class)
class MeritevViewModel(
    application: Application,
    private val repository: MeritevRepository,
    private val firestoreRepository: FirestoreRepository,
    private val sensorRepository: SensorRepository
) : AndroidViewModel(application) {

    private val _currentUserId = MutableStateFlow<String?>(null)
    private val _statusMessage = MutableSharedFlow<String>()
    private val _zadnjaShranjenaId = MutableStateFlow<Int?>(null)
    private val _operationResult = MutableStateFlow<OperationResult?>(null)
    private val _lastSyncCount = MutableStateFlow<Int?>(null)

    val statusMessage = _statusMessage.asSharedFlow()
    val zadnjaShranjenaId: StateFlow<Int?> = _zadnjaShranjenaId.asStateFlow()
    val operationResult: StateFlow<OperationResult?> = _operationResult.asStateFlow()
    val lastSyncCount: StateFlow<Int?> = _lastSyncCount.asStateFlow()

    val vseMeritve: StateFlow<List<Meritev>> = _currentUserId
        .flatMapLatest { userId ->
            if (userId.isNullOrBlank()) emptyFlow() else repository.getMeritveByUser(userId)
        }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // Real-time cloud meritve (Firestore SnapshotListener)
    val cloudMeritve: StateFlow<List<Meritev>> = _currentUserId
        .flatMapLatest { userId ->
            if (userId.isNullOrBlank()) emptyFlow() else firestoreRepository.getMeritveByUser(userId)
        }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // Statistics computed from cloud data (real-time)
    val statistics: StateFlow<Statistics> = cloudMeritve
        .map { meritve -> Statistics.fromMeritve(meritve) }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = Statistics()
        )

    fun setCurrentUser(userId: String?) {
        _currentUserId.value = userId
    }

    fun getMeritevById(id: Int): Flow<Meritev?> = repository.getMeritevById(id)

    fun vstavi(meritev: Meritev, onInserted: (Int) -> Unit = {}) {
        viewModelScope.launch {
            try {
                val userId = _currentUserId.value ?: ""
                val withUser = meritev.copy(userId = userId)
                val insertedId = repository.vstavi(withUser).toInt()

                if (userId.isNotBlank()) {
                    runCatching { firestoreRepository.insertMeritev(withUser) }
                        .onSuccess { firestoreId ->
                            repository.posodobi(withUser.copy(id = insertedId, firestoreId = firestoreId))
                        }
                        .onFailure {
                            _statusMessage.emit(
                                getApplication<Application>().getString(
                                    R.string.shranjeno_lokalno_oblak_nedosegljiv
                                )
                            )
                        }
                }

                _zadnjaShranjenaId.value = insertedId
                onInserted(insertedId)
                _operationResult.value = OperationResult.INSERTED
            } catch (_: Exception) {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun posodobi(meritev: Meritev) {
        viewModelScope.launch {
            try {
                repository.posodobi(meritev)
                _operationResult.value = OperationResult.UPDATED
            } catch (_: Exception) {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun izbrisi(meritev: Meritev) {
        viewModelScope.launch {
            try {
                repository.izbrisi(meritev)
                if (meritev.firestoreId.isNotBlank()) {
                    runCatching { firestoreRepository.deleteMeritev(meritev.firestoreId) }
                }
                _operationResult.value = OperationResult.DELETED
            } catch (_: Exception) {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun syncFromFirestore() {
        val uid = _currentUserId.value ?: return
        viewModelScope.launch {
            runCatching {
                val remoteMeritve = firestoreRepository.fetchAllByUser(uid)
                repository.deleteAllByUser(uid)
                remoteMeritve.forEach { repository.vstavi(it.copy(id = 0, userId = uid)) }
                remoteMeritve.size
            }.onSuccess { syncedCount ->
                _lastSyncCount.value = syncedCount
                _operationResult.value = OperationResult.SYNCED
            }.onFailure {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun preberiSrcniUtrip(onValue: (Int) -> Unit) {
        viewModelScope.launch {
            val value = if (sensorRepository.hasHeartRateSensor()) {
                sensorRepository.readHeartRateFromSensor() ?: sensorRepository.readHeartRateFromApi()
            } else {
                sensorRepository.readHeartRateFromApi()
            }
            onValue(value)
        }
    }

    fun preberiSpO2(onValue: (Int) -> Unit) {
        viewModelScope.launch {
            onValue(sensorRepository.readSpO2FromApi())
        }
    }

    fun preberiTemperaturo(onValue: (Double) -> Unit) {
        viewModelScope.launch {
            onValue(sensorRepository.readTemperatureFromApi())
        }
    }

    fun clearOperationResult() {
        _operationResult.value = null
        _lastSyncCount.value = null
    }

    enum class OperationResult {
        INSERTED, UPDATED, DELETED, SYNCED, ERROR
    }
}

class MeritevViewModelFactory(
    private val application: Application,
    private val repository: MeritevRepository,
    private val firestoreRepository: FirestoreRepository,
    private val sensorRepository: SensorRepository
) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(MeritevViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return MeritevViewModel(
                application = application,
                repository = repository,
                firestoreRepository = firestoreRepository,
                sensorRepository = sensorRepository
            ) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

package com.example.health_app.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.health_app.R
import com.example.health_app.data.FirestoreRepository
import com.example.health_app.data.Meritev
import com.example.health_app.data.MeritevRepository
import com.example.health_app.data.Statistics
import com.example.health_app.ml.GeminiHelper
import com.example.health_app.ml.HealthClassifier
import com.example.health_app.ml.HealthPrediction
import com.example.health_app.ml.HealthStatus
import com.example.health_app.network.SensorRepository
import java.util.Locale
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.emptyFlow
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

@OptIn(kotlinx.coroutines.ExperimentalCoroutinesApi::class)
class MeritevViewModel(
    application: Application,
    private val repository: MeritevRepository,
    private val firestoreRepository: FirestoreRepository,
    private val sensorRepository: SensorRepository,
    private val healthClassifier: HealthClassifier,
    private val geminiHelper: GeminiHelper
) : AndroidViewModel(application) {

    private val _currentUserId = MutableStateFlow<String?>(null)
    private val _statusMessage = MutableSharedFlow<String>()
    private val _zadnjaShranjenaId = MutableStateFlow<Int?>(null)
    private val _operationResult = MutableStateFlow<OperationResult?>(null)
    private val _lastSyncCount = MutableStateFlow<Int?>(null)
    private val _healthPrediction = MutableStateFlow<HealthPrediction?>(null)
    private val _aiSummaryState = MutableStateFlow(AiSummaryUiState())

    val statusMessage = _statusMessage.asSharedFlow()
    val zadnjaShranjenaId: StateFlow<Int?> = _zadnjaShranjenaId.asStateFlow()
    val operationResult: StateFlow<OperationResult?> = _operationResult.asStateFlow()
    val lastSyncCount: StateFlow<Int?> = _lastSyncCount.asStateFlow()
    val healthPrediction: StateFlow<HealthPrediction?> = _healthPrediction.asStateFlow()
    val aiSummaryState: StateFlow<AiSummaryUiState> = _aiSummaryState.asStateFlow()

    val vseMeritve: StateFlow<List<Meritev>> = _currentUserId
        .flatMapLatest { userId ->
            if (userId.isNullOrBlank()) emptyFlow() else repository.getMeritveByUser(userId)
        }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // Real-time cloud meritve (Firestore SnapshotListener)
    val cloudMeritve: StateFlow<List<Meritev>> = _currentUserId
        .flatMapLatest { userId ->
            if (userId.isNullOrBlank()) emptyFlow() else firestoreRepository.getMeritveByUser(userId)
        }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = emptyList()
        )

    // Statistics computed from cloud data (real-time)
    val statistics: StateFlow<Statistics> = cloudMeritve
        .map { meritve -> Statistics.fromMeritve(meritve) }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = Statistics()
        )

    fun setCurrentUser(userId: String?) {
        _currentUserId.value = userId
    }

    fun getMeritevById(id: Int): Flow<Meritev?> = repository.getMeritevById(id)

    fun vstavi(meritev: Meritev, onInserted: (Int) -> Unit = {}) {
        viewModelScope.launch {
            try {
                val userId = _currentUserId.value ?: ""
                val withUser = meritev.copy(userId = userId)
                val insertedId = repository.vstavi(withUser).toInt()

                if (userId.isNotBlank()) {
                    runCatching { firestoreRepository.insertMeritev(withUser) }
                        .onSuccess { firestoreId ->
                            repository.posodobi(withUser.copy(id = insertedId, firestoreId = firestoreId))
                        }
                        .onFailure {
                            _statusMessage.emit(
                                getApplication<Application>().getString(
                                    R.string.shranjeno_lokalno_oblak_nedosegljiv
                                )
                            )
                        }
                }

                _zadnjaShranjenaId.value = insertedId
                _healthPrediction.value = healthClassifier.classify(
                    hr = withUser.srcniUtrip,
                    spo2 = withUser.spO2,
                    temp = withUser.temperatura
                )
                onInserted(insertedId)
                _operationResult.value = OperationResult.INSERTED
            } catch (_: Exception) {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun posodobi(meritev: Meritev) {
        viewModelScope.launch {
            try {
                repository.posodobi(meritev)
                _operationResult.value = OperationResult.UPDATED
            } catch (_: Exception) {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun izbrisi(meritev: Meritev) {
        viewModelScope.launch {
            try {
                repository.izbrisi(meritev)
                if (meritev.firestoreId.isNotBlank()) {
                    runCatching { firestoreRepository.deleteMeritev(meritev.firestoreId) }
                }
                _operationResult.value = OperationResult.DELETED
            } catch (_: Exception) {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun syncFromFirestore() {
        val uid = _currentUserId.value ?: return
        viewModelScope.launch {
            runCatching {
                val remoteMeritve = firestoreRepository.fetchAllByUser(uid)
                repository.deleteAllByUser(uid)
                remoteMeritve.forEach { repository.vstavi(it.copy(id = 0, userId = uid)) }
                remoteMeritve.size
            }.onSuccess { syncedCount ->
                _lastSyncCount.value = syncedCount
                _operationResult.value = OperationResult.SYNCED
            }.onFailure {
                _operationResult.value = OperationResult.ERROR
            }
        }
    }

    fun preberiSrcniUtrip(onValue: (Int) -> Unit) {
        viewModelScope.launch {
            val value = if (sensorRepository.hasHeartRateSensor()) {
                sensorRepository.readHeartRateFromSensor() ?: sensorRepository.readHeartRateFromApi()
            } else {
                sensorRepository.readHeartRateFromApi()
            }
            onValue(value)
        }
    }

    fun preberiSpO2(onValue: (Int) -> Unit) {
        viewModelScope.launch {
            onValue(sensorRepository.readSpO2FromApi())
        }
    }

    fun preberiTemperaturo(onValue: (Double) -> Unit) {
        viewModelScope.launch {
            onValue(sensorRepository.readTemperatureFromApi())
        }
    }

    fun classifyMeasurement(meritev: Meritev) {
        _healthPrediction.value = healthClassifier.classify(
            hr = meritev.srcniUtrip,
            spo2 = meritev.spO2,
            temp = meritev.temperatura
        )
    }

    fun getHealthStatusLabel(status: HealthStatus): Int {
        return when (status) {
            HealthStatus.NORMAL -> R.string.normalno
            HealthStatus.ELEVATED -> R.string.povisano
            HealthStatus.CRITICAL -> R.string.kriticno
        }
    }

    fun generateAiSummary() {
        val meritve = cloudMeritve.value.ifEmpty { vseMeritve.value }
        viewModelScope.launch {
            _aiSummaryState.value = AiSummaryUiState(isLoading = true)
            runCatching { geminiHelper.generateSummary(meritve) }
                .onSuccess { summary ->
                    _aiSummaryState.value = AiSummaryUiState(summary = summary)
                }
                .onFailure { error ->
                    _aiSummaryState.value = AiSummaryUiState(
                        summary = buildFallbackAiSummary(meritve),
                        error = if (meritve.isEmpty()) {
                            error.localizedMessage ?: getApplication<Application>().getString(R.string.ai_povzetek_napaka)
                        } else {
                            null
                        }
                    )
                }
        }
    }

    private fun buildFallbackAiSummary(meritve: List<Meritev>): String {
        if (meritve.isEmpty()) return getApplication<Application>().getString(R.string.ni_meritev)

        val zadnje = meritve.sortedByDescending { it.datum }.take(10)
        val avgHr = zadnje.map { it.srcniUtrip }.average()
        val avgSpo2 = zadnje.map { it.spO2 }.average()
        val avgTemp = zadnje.map { it.temperatura }.average()

        return getApplication<Application>().getString(
            R.string.ai_local_fallback,
            zadnje.size,
            String.format(Locale.getDefault(), "%.0f", avgHr),
            String.format(Locale.getDefault(), "%.0f", avgSpo2),
            String.format(Locale.getDefault(), "%.1f", avgTemp)
        )
    }

    fun clearOperationResult() {
        _operationResult.value = null
        _lastSyncCount.value = null
    }

    enum class OperationResult {
        INSERTED, UPDATED, DELETED, SYNCED, ERROR
    }

    data class AiSummaryUiState(
        val summary: String? = null,
        val isLoading: Boolean = false,
        val error: String? = null
    )
}

class MeritevViewModelFactory(
    private val application: Application,
    private val repository: MeritevRepository,
    private val firestoreRepository: FirestoreRepository,
    private val sensorRepository: SensorRepository,
    private val healthClassifier: HealthClassifier,
